const items = $input.all();
const results = [];

// Funnel stage progression map
const funnelStages = {
  'New_Lead':      { next: 'Contacted',     minScore: 0  },
  'Contacted':     { next: 'Qualified',     minScore: 50 },
  'Qualified':     { next: 'Proposal_Sent', minScore: 70 },
  'Proposal_Sent': { next: 'Negotiation',   minScore: 75 },
  'Negotiation':   { next: 'Closed_Won',    minScore: 85 },
  'Closed_Won':    { next: 'Closed_Won',    minScore: 100}
};

for (const item of items) {
  const d = item.json;

  // ── VALIDATE required fields ──
  const missing = [];
  if (!d.event_id)    missing.push('event_id');
  if (!d.from_email)  missing.push('from_email');
  if (!d.full_name)   missing.push('full_name');
  if (!d.current_stage) missing.push('current_stage');

  if (missing.length > 0) {
    results.push({
      json: {
        ...d,
        update_status: 'invalid',
        skip: true,
        reason: 'Missing: ' + missing.join(', ')
      }
    });
    continue;
  }

  // ── NORMALIZE email ──
  const email = (d.from_email || '')
    .toLowerCase().trim();

  // ── NORMALIZE phone ──
  let phone = (d.phone || '').replace(/\s+/g, '');
  if (phone && !phone.startsWith('+')) {
    phone = '+' + phone;
  }

  // ── NORMALIZE stage ──
  const currentStage = (d.current_stage || '')
    .trim()
    .replace(/\s+/g, '_');

  // ── CALCULATE next funnel stage ──
  const stageConfig = funnelStages[currentStage] || 
    { next: currentStage, minScore: 0 };

  const leadScore = parseInt(d.lead_score) || 0;
  const canAdvance = leadScore >= stageConfig.minScore;

  const nextStage = canAdvance 
    ? stageConfig.next 
    : currentStage; // stay in current stage if score too low

  // ── CALCULATE updated lead score ──
  // Boost score slightly on each processing run
  const updatedScore = Math.min(100, leadScore + 5);

  // ── DETERMINE new status ──
  let newStatus = 'updated';
  if (nextStage === 'Closed_Won') newStatus = 'closed';
  if (!canAdvance) newStatus = 'stalled';

  results.push({
    json: {
      id: d.id,
      event_id: d.event_id,
      from_email: email,
      full_name: d.full_name,
      phone: phone,
      current_stage: currentStage,
      next_stage: nextStage,
      lead_score: updatedScore,
      update_status: newStatus,
      can_advance: canAdvance,
      skip: false,
      updated_at: new Date().toISOString()
    }
  });
}

return results;
